package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.Sleutel;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RszTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.SleutelSamenNemer;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.sleutel.SleutelNaceCode;
import be.schaubroeck.lpb.rkm.rekenmotor.util.sleutel.SleutelWerkgeversCategorie;
import be.schaubroeck.lpb.rkm.rekenmotor.util.sleutel.SleutelWerknemersKengetal;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.RszPlafondPercentage;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.service.RszPlafondPercentageService;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Collection;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

@AllArgsConstructor
public class BerekenPatronaleVermindering707 {

    private static final Set<Integer> PRESTATIE_CODE_IN_AANMERKING = ImmutableSet.of(1, 2, 3, 4, 5, 6, 7, 9, 51, 61, 62, 65, 66);
    public static final Set<Sleutel<?>> VERMINDERING_707_SLEUTEL =
            ImmutableSet.of(SleutelWerkgeversCategorie.INSTANCE, SleutelWerknemersKengetal.INSTANCE, SleutelNaceCode.INSTANCE);

    private static final SleutelSamenNemer AGGREGATOR = new SleutelSamenNemer();

    private final LoonElementManager elementManager;
    private final LoonElementManager prevElementManager;
    private final RekenTijd rekenTijd;
    private final RszPlafondPercentageService rszPlafondPercentageService;
    private final HeeftPatronaleVermindering707 heeftVermindering;
    private final boolean dmfaAangifteAanwezig;

    private static final Set<RekenPatronaalRszKey> PATRONALE_VERMINDERINGEN =
            ImmutableSet.of(RekenPatronaalRszKey.VERMINDERING_PATRONALE_BIJDRAGE_RSZ_KEY, RekenPatronaalRszKey.VERMINDERING_PATRONALE_BIJDRAGE_ONTHAAL_OUDERS_KEY);
    private static final BigDecimal PERCENTAGE_707 = new BigDecimal("0.0707");

    public BerekenPatronaleVermindering707(
            RszPlafondPercentageService rszPlafondPercentageService, ConstantManager constantManager, LoonElementManager elementManager,
            LoonElementManager prevElementManager, boolean dmfaAangifteAanwezig, RekenTijd rekenTijd) {
        this.elementManager = elementManager;
        this.prevElementManager = prevElementManager;
        this.rekenTijd = rekenTijd;
        this.rszPlafondPercentageService = rszPlafondPercentageService;
        this.heeftVermindering = new HeeftPatronaleVermindering707(constantManager, rekenTijd);
        this.dmfaAangifteAanwezig = dmfaAangifteAanwezig;
    }

    public void bereken(Opdracht opdracht) {
        if (heeftVermindering.isActief(rekenTijd, dmfaAangifteAanwezig)) {
            List<SleutelGegevens> aggregaten = AGGREGATOR.neemSamenVoorSleutel(opdracht, VERMINDERING_707_SLEUTEL);
            aggregaten.stream().filter(heeftVermindering::check).forEach(this::bereken);
        } else if (heeftVermindering.isOvernameNodig(rekenTijd, dmfaAangifteAanwezig) && prevElementManager != null) {
            Collection<LoonElement> prevElementen = prevElementManager.getOpdrachtsElementen(opdracht);
            RekenTools.overnemenVanVorigeBerekening(RekenPatronaalRszKey.VERMINDERING_PATRONALE_BIJDRAGE_7_07_KEY, elementManager, prevElementen);
        }
    }

    private void bereken(SleutelGegevens gegeven) {
        Collection<LoonElement> elementen = bepaalLoonElementen(gegeven);
        Money totaleVermindering = elementen.stream().map(this::bepaalTotalePatronaleBijdrageVermindering).reduce(Money.ZERO, Money::add);
        Money totaleBasisPatronaleBijdrage = elementen.stream().map(this::getBasisPatronaleBijdrage).reduce(Money.ZERO, Money::add);
        Money plafondPatronaleBijdrage = berekenPlafondPatronaleBijdrage(totaleBasisPatronaleBijdrage, gegeven);
        Money basis = plafondPatronaleBijdrage.subtract(totaleVermindering).max(Money.ZERO);
        Money vermindering = basis.multiply(PERCENTAGE_707).round(2);
        BedragVerdelerFactory.verdeelBedragVolgensBasisPut(RekenPatronaalRszKey.VERMINDERING_PATRONALE_BIJDRAGE_7_07_KEY, vermindering,
                RekenBasisRszKey.BASIS_RSZ_KEY, totaleBasisPatronaleBijdrage, elementen);
    }

    private Collection<LoonElement> bepaalLoonElementen(SleutelGegevens gegeven) {
        Collection<LoonElement> elementen = elementManager.getOpperElementen(gegeven.getOppers());
        return elementen.stream().filter(this::komtInAanmerkingLoonElement).collect(Collectors.toCollection(LoonElement::createSortedSet));
    }

    private boolean komtInAanmerkingLoonElement(LoonElement element) {
        AardKodeExtensie aardKodeExtensie = element.getAardKodeExtensie();
        DmfapplWnkengetal werknemersKengetal = element.getOpper().getRszppo().getWerknemersKengetal();
        WerknemersKengetalLooncodeDmfa werknemersKengetalLooncodeDmfa = new WerknemersKengetalLooncodeDmfa(aardKodeExtensie, werknemersKengetal);
        return PRESTATIE_CODE_IN_AANMERKING.contains(werknemersKengetalLooncodeDmfa.getLooncodeCode());
    }

    private Money bepaalTotalePatronaleBijdrageVermindering(LoonElement element) {
        Money totaal = Money.ZERO;
        for (RekenPatronaalRszKey key : PATRONALE_VERMINDERINGEN) {
            totaal = totaal.add(element.getPropertyMoney(key));
        }
        return totaal;
    }

    private Money berekenPlafondPatronaleBijdrage(Money basis, SleutelGegevens gegevens) {
        BigDecimal percentage = bepaalPlafondPercentagePatronaleBijdrage(gegevens);
        return basis.multiply(percentage).round(2);
    }

    public static final int SCHUIF_FACTOR_100 = 2;

    public BigDecimal bepaalPlafondPercentagePatronaleBijdrage(SleutelGegevens gegevens) {
        BigDecimal bijdragePercentage = BigDecimal.ZERO;
        DmfapplWnkengetal werknemersKengetal = gegevens.getWerknemersKengetal();
        LocalDate zoekDatum = TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode);
        LocalDate datum = RszTools.zoekDatumAanpassenVoorVervallenWnkKengetallen(werknemersKengetal, zoekDatum);

        RszPlafondPercentage
                constante = rszPlafondPercentageService.getByWerkgeversCategorieEnWerknemersKengetalEnDatum(gegevens.getWerkgeversCategorie(), werknemersKengetal, datum);

        if (constante != null) {
            bijdragePercentage = constante.getWerkgeversPercentage();
        }
        return bijdragePercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

    private Money getBasisPatronaleBijdrage(LoonElement element) {
        return element.getPropertyMoney(RekenBasisRszKey.BASIS_RSZ_KEY);
    }
}
